select  seth.id as id,seth.bankreconciliationschemecode as bankreconciliationschemecode,seth.reconciliationdatasource as reconciliationdatasource,seth.enableDate as enableDate,seth.accentity as accentity,
       setb.currency as currency,setb.bankaccount as bankaccount,setb.acc_book as accbook_b,setb.enable_status as enableStatus_b,setb.use_org as useorg,setb.accentity_raw as accentityRaw
from cmp_bankreconciliationsetting_b setb left join cmp_bankreconciliationsetting seth on setb.mainid=seth.id
where
setb.ytenant_id = #{ytenant_id}

    and setb.acc_book in

        #{item}



    and setb.bankaccount in

        #{item}



    and setb.currency in

        #{item}



    and setb.use_org in

        #{item}



    and  seth.reconciliationdatasource = #{reconciliationdatasource}


    and  seth.reconciliationdatasource = 1


    and  seth.enableDate <= CAST(#{enableDate} AS DATE)


    and  (setb.enable_date >= CAST(#{stopDate} AS DATE) or setb.enable_date is null)
